namespace JumpHeightMod
{
    [BepInPlugin(PluginInfo.PLUGIN_GUID, PluginInfo.PLUGIN_NAME, PluginInfo.PLUGIN_VERSION)]
    public class JumpHeightPlugin : BaseUnityPlugin
    {
        public const string PLUGIN_GUID = "com.example.jumpheightmod";
        public const string PLUGIN_NAME = "Jump Height Mod";
        public const string PLUGIN_VERSION = "1.0.0";

        public static ConfigEntry<float> JumpHeightMultiplier;
        public static ConfigEntry<bool> ModEnabled;

        private Harmony _harmony;

        private void Awake()
        {
            ModEnabled = Config.Bind(
                "General",
                "Enabled",
                true,
                "Enable or disable the Jump Height Mod."
            );

            JumpHeightMultiplier = Config.Bind(
                "Physics",
                "JumpHeightMultiplier",
                1.5f,
                new ConfigDescription(
                    "Multiplier applied to the player's jump force. Default game value is 1.0.",
                    new AcceptableValueRange<float>(0.1f, 10.0f)
                )
            );

            if (ModEnabled.Value)
            {
                _harmony = new Harmony(PLUGIN_GUID);
                _harmony.PatchAll();
                Logger.LogInfo($"{PLUGIN_NAME} v{PLUGIN_VERSION} loaded. Jump multiplier: {JumpHeightMultiplier.Value}x");
            }
            else
            {
                Logger.LogInfo($"{PLUGIN_NAME} is disabled via config.");
            }
        }

        private void OnDestroy()
        {
            _harmony?.UnpatchSelf();
        }
    }

    [HarmonyPatch(typeof(PlayerController), nameof(PlayerController.Jump))]
    public static class PlayerController_Jump_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix(PlayerController __instance, ref float ___jumpForce)
        {
            if (!JumpHeightPlugin.ModEnabled.Value) return true;
            ___jumpForce *= JumpHeightPlugin.JumpHeightMultiplier.Value;
            return true;
        }
    }
}

