namespace MovementConfigMod
{
    [BepInPlugin("com.example.movementconfig", "Movement Config Mod", "1.0.0")]
    public class MovementConfigPlugin : BaseUnityPlugin
    {
        public static ConfigEntry<bool> ModEnabled;
        public static ConfigEntry<float> WalkSpeed;
        public static ConfigEntry<float> SprintSpeed;
        public static ConfigEntry<bool> SprintingAllowed;
        public static ConfigEntry<KeyboardShortcut> SprintKey;

        private static Harmony _harmony;

        private void Awake()
        {
            ModEnabled = Config.Bind("General", "Enabled", true, "Master toggle for the Movement Config Mod.");

            WalkSpeed = Config.Bind(
                "Movement",
                "WalkSpeed",
                5.0f,
                new ConfigDescription("Player walk speed.", new AcceptableValueRange<float>(1f, 50f))
            );

            SprintSpeed = Config.Bind(
                "Movement",
                "SprintSpeed",
                10.0f,
                new ConfigDescription("Player sprint speed.", new AcceptableValueRange<float>(1f, 100f))
            );

            SprintingAllowed = Config.Bind(
                "Movement",
                "SprintingAllowed",
                true,
                "If false, the player cannot sprint regardless of input."
            );

            SprintKey = Config.Bind(
                "Movement",
                "SprintKey",
                new KeyboardShortcut(KeyCode.LeftShift),
                "Key held to sprint."
            );

            if (ModEnabled.Value)
            {
                _harmony = new Harmony("com.example.movementconfig");
                _harmony.PatchAll();
                Logger.LogInfo("Movement Config Mod loaded.");
                Logger.LogInfo($"  Walk: {WalkSpeed.Value}, Sprint: {SprintSpeed.Value}, SprintAllowed: {SprintingAllowed.Value}");
            }
        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    [HarmonyPatch(typeof(PlayerController), "Update")]
    public static class PlayerController_Update_Patch
    {
        [HarmonyPostfix]
        public static void Postfix(PlayerController __instance)
        {
            if (!MovementConfigPlugin.ModEnabled.Value) return;

            bool isSprinting = MovementConfigPlugin.SprintingAllowed.Value
                && MovementConfigPlugin.SprintKey.Value.IsPressed();

            float targetSpeed = isSprinting
                ? MovementConfigPlugin.SprintSpeed.Value
                : MovementConfigPlugin.WalkSpeed.Value;

            __instance.moveSpeed = targetSpeed;
        }
    }
}

