namespace CheatConfigMod
{
    [BepInPlugin("com.example.cheatconfig", "Cheat Config Mod", "1.2.0")]
    public class CheatConfigPlugin : BaseUnityPlugin
    {
        public static CheatConfigPlugin Instance { get; private set; }

        public static ConfigEntry<bool> GodMode;
        public static ConfigEntry<bool> InfiniteAmmo;
        public static ConfigEntry<string> HudColorHex;

        private static Color _parsedHudColor = Color.white;
        private static Harmony _harmony;

        private void Awake()
        {
            Instance = this;

            GodMode = Config.Bind("Cheats", "GodMode", false, "Player takes no damage when enabled.");
            InfiniteAmmo = Config.Bind("Cheats", "InfiniteAmmo", false, "Prevents ammo from being consumed.");
            HudColorHex = Config.Bind(
                "Visual",
                "HudColorHex",
                "#FFFFFF",
                "Hex color string to tint the HUD (e.g. #FF0000 for red)."
            );

            if (ColorUtility.TryParseHtmlString(HudColorHex.Value, out Color parsed))
                _parsedHudColor = parsed;
            else
                Logger.LogWarning($"Invalid HUD color hex '{HudColorHex.Value}'. Using white.");

            HudColorHex.SettingChanged += (sender, args) =>
            {
                if (ColorUtility.TryParseHtmlString(HudColorHex.Value, out Color c))
                    _parsedHudColor = c;
            };

            _harmony = new Harmony("com.example.cheatconfig");
            _harmony.PatchAll();
            Logger.LogInfo("Cheat Config Mod loaded.");
        }

        public static Color GetHudColor() => _parsedHudColor;

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    [HarmonyPatch(typeof(PlayerHealth), nameof(PlayerHealth.TakeDamage))]
    public static class PlayerHealth_TakeDamage_GodMode_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix()
        {
            if (CheatConfigPlugin.GodMode.Value)
            {
                return false;
            }
            return true;
        }
    }

    [HarmonyPatch(typeof(WeaponController), nameof(WeaponController.ConsumeAmmo))]
    public static class WeaponController_ConsumeAmmo_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix()
        {
            return !CheatConfigPlugin.InfiniteAmmo.Value;
        }
    }

    [HarmonyPatch(typeof(HUDManager), "Start")]
    public static class HUDManager_Start_Patch
    {
        [HarmonyPostfix]
        public static void Postfix(HUDManager __instance)
        {
            Image[] images = __instance.GetComponentsInChildren<Image>(true);
            foreach (Image img in images)
            {
                img.color = CheatConfigPlugin.GetHudColor();
            }
        }
    }
}

