{
    [BepInPlugin("com.example.enemyattackcancel", "Enemy Attack Cancel Mod", "1.0.0")]
    public class EnemyAttackCancelPlugin : BaseUnityPlugin
    {
        private Harmony _harmony;

        private void Awake()
        {
            _harmony = new Harmony("com.example.enemyattackcancel");
            _harmony.PatchAll();
            Logger.LogInfo("Enemy Attack Cancel Mod loaded.");
        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    /// <summary>
    /// Prefix patch on EnemyAI.Attack(PlayerController target).
    /// Cancels the attack entirely (returns false) if the target player is invisible.
    /// </summary>
    [HarmonyPatch(typeof(EnemyAI), nameof(EnemyAI.Attack))]
    public static class EnemyAI_Attack_Prefix_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix(EnemyAI __instance, PlayerController target)
        {
            if (target == null) return true;

            PlayerStatusEffects statusEffects = target.GetComponent<PlayerStatusEffects>();
            if (statusEffects != null && statusEffects.IsInvisible)
            {
                Debug.Log($"[EnemyAttackCancelMod] {__instance.name} attempted to attack invisible player. Attack cancelled.");
                return false;
            }

            return true;
        }
    }

    /// <summary>
    /// Prefix patch on EnemyAI.DetectPlayer to also suppress detection while invisible.
    /// </summary>
    [HarmonyPatch(typeof(EnemyAI), "DetectPlayer")]
    public static class EnemyAI_DetectPlayer_Prefix_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix(EnemyAI __instance, PlayerController player, ref bool __result)
        {
            if (player == null) return true;

            PlayerStatusEffects statusEffects = player.GetComponent<PlayerStatusEffects>();
            if (statusEffects != null && statusEffects.IsInvisible)
            {
                __result = false;
                return false;
            }

            return true;
        }
    }
}

