namespace DamageMultiplierMod
{
    [BepInPlugin("com.example.damagemultiplier", "Damage Multiplier Mod", "1.0.0")]
    public class DamageMultiplierPlugin : BaseUnityPlugin
    {
        public static ConfigEntry<float> PlayerDamageMultiplier;
        public static ConfigEntry<float> IncomingDamageMultiplier;
        public static ConfigEntry<bool> ModEnabled;

        private Harmony _harmony;

        private void Awake()
        {
            ModEnabled = Config.Bind("General", "Enabled", true, "Enable or disable this mod.");

            PlayerDamageMultiplier = Config.Bind(
                "Damage",
                "PlayerDamageMultiplier",
                2.0f,
                new ConfigDescription("Multiplier for damage dealt by the player.", new AcceptableValueRange<float>(0f, 20f))
            );

            IncomingDamageMultiplier = Config.Bind(
                "Damage",
                "IncomingDamageMultiplier",
                0.5f,
                new ConfigDescription("Multiplier for damage received by the player (0.5 = half damage).", new AcceptableValueRange<float>(0f, 5f))
            );

            if (ModEnabled.Value)
            {
                _harmony = new Harmony("com.example.damagemultiplier");
                _harmony.PatchAll();
                Logger.LogInfo("Damage Multiplier Mod loaded.");
            }
        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    [HarmonyPatch(typeof(CombatSystem), "CalculatePlayerDamage")]
    public static class CombatSystem_CalculatePlayerDamage_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix(ref float baseDamage, bool isCritical)
        {
            if (!DamageMultiplierPlugin.ModEnabled.Value) return true;

            baseDamage *= DamageMultiplierPlugin.PlayerDamageMultiplier.Value;
            Debug.Log($"[DamageMultiplierMod] Player damage modified to: {baseDamage} (isCrit: {isCritical})");
            return true;
        }
    }

    [HarmonyPatch(typeof(PlayerHealth), "ReceiveDamage")]
    public static class PlayerHealth_ReceiveDamage_Patch
    {
        [HarmonyPrefix]
        public static bool Prefix(ref float damage)
        {
            if (!DamageMultiplierPlugin.ModEnabled.Value) return true;

            damage *= DamageMultiplierPlugin.IncomingDamageMultiplier.Value;
            damage = Mathf.Max(0f, damage);
            Debug.Log($"[DamageMultiplierMod] Incoming damage modified to: {damage}");
            return true;
        }
    }
}

