namespace InfiniteLootMod
{
    [BepInPlugin("com.example.infiniteloot", "Infinite Loot Mod", "1.0.0")]
    public class InfiniteLootPlugin : BaseUnityPlugin
    {
        public static ConfigEntry<string> TargetItemName;
        public static ConfigEntry<float> RespawnDelay;
        public static InfiniteLootPlugin Instance { get; private set; }

        private Harmony _harmony;

        private void Awake()
        {
            Instance = this;

            TargetItemName = Config.Bind(
                "Loot",
                "TargetItemName",
                "HealthPotion",
                "Exact name of the item to duplicate on pickup."
            );

            RespawnDelay = Config.Bind(
                "Loot",
                "RespawnDelay",
                5.0f,
                new ConfigDescription("Seconds before the item respawns after pickup.", new AcceptableValueRange<float>(0f, 60f))
            );

            _harmony = new Harmony("com.example.infiniteloot");
            _harmony.PatchAll();
            Logger.LogInfo($"Infinite Loot Mod loaded. Targeting item: '{TargetItemName.Value}'");
        }

        public void ScheduleRespawn(GameObject itemPrefab, Vector3 position, Quaternion rotation)
        {
            StartCoroutine(RespawnCoroutine(itemPrefab, position, rotation));
        }

        private IEnumerator RespawnCoroutine(GameObject prefab, Vector3 pos, Quaternion rot)
        {
            yield return new WaitForSeconds(RespawnDelay.Value);
            GameObject spawned = Instantiate(prefab, pos, rot);
            Logger.LogInfo($"[InfiniteLootMod] Respawned '{prefab.name}' at {pos}");
        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    [HarmonyPatch(typeof(LootItem), nameof(LootItem.OnPickedUp))]
    public static class LootItem_OnPickedUp_Prefix_Patch
    {
        [HarmonyPrefix]
        public static void Prefix(LootItem __instance)
        {
            if (__instance.itemData == null) return;
            if (__instance.itemData.itemName != InfiniteLootPlugin.TargetItemName.Value) return;

            Vector3 spawnPos = __instance.transform.position;
            Quaternion spawnRot = __instance.transform.rotation;
            GameObject prefabRef = __instance.gameObject;

            InfiniteLootPlugin.Instance.ScheduleRespawn(prefabRef, spawnPos, spawnRot);
            Debug.Log($"[InfiniteLootMod] Scheduled respawn for '{__instance.itemData.itemName}' in {InfiniteLootPlugin.RespawnDelay.Value}s");
        }
    }
}

