    [BepInPlugin("com.example.statsoverlay", "Stats Overlay Mod", "1.0.0")]
    public class StatsOverlayPlugin : BaseUnityPlugin
    {
        public static StatsOverlayPlugin Instance { get; private set; }
        private Harmony _harmony;

        public static string OverlayText { get; set; } = "Waiting for stats...";

        private void Awake()
        {
            Instance = this;
            _harmony = new Harmony("com.example.statsoverlay");
            _harmony.PatchAll();
            Logger.LogInfo("Stats Overlay Mod loaded.");
        }

        private void OnGUI()
        {
            GUIStyle style = new GUIStyle(GUI.skin.box);
            style.fontSize = 14;
            style.normal.textColor = Color.green;
            style.alignment = TextAnchor.UpperLeft;

            Vector2 size = style.CalcSize(new GUIContent(OverlayText));
            float padding = 8f;
            Rect rect = new Rect(10, 10, size.x + padding * 2, size.y + padding * 2);

