        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    [HarmonyPatch(typeof(StatsManager), nameof(StatsManager.UpdateStats))]
    public static class StatsManager_UpdateStats_Postfix_Patch
    {
        [HarmonyPostfix]
        public static void Postfix(StatsManager __instance)
        {
            if (__instance == null) return;

            float hp = __instance.CurrentHealth;
            float maxHp = __instance.MaxHealth;
            float stamina = __instance.CurrentStamina;
            float maxStamina = __instance.MaxStamina;
            int level = __instance.PlayerLevel;
            int xp = __instance.CurrentXP;
            int xpToNext = __instance.XPToNextLevel;

            StatsOverlayPlugin.OverlayText =
                $"=== Player Stats ===\n" +
                $"Level : {level}\n" +
                $"XP    : {xp} / {xpToNext}\n" +
                $"HP    : {hp:F1} / {maxHp:F1}\n" +
                $"Stamina: {stamina:F1} / {maxStamina:F1}";
