namespace InventoryTrackerMod
{
    [BepInPlugin("com.example.inventorytracker", "Inventory Tracker Mod", "1.0.0")]
    public class InventoryTrackerPlugin : BaseUnityPlugin
    {
        public static InventoryTrackerPlugin Instance { get; private set; }
        public static Dictionary<string, int> ItemPickupCounts { get; private set; } = new Dictionary<string, int>();

        private Harmony _harmony;

        private void Awake()
        {
            Instance = this;
            _harmony = new Harmony("com.example.inventorytracker");
            _harmony.PatchAll();
            Logger.LogInfo("Inventory Tracker Mod loaded.");
        }

        public static void RecordItemAdded(string itemName, int quantity, bool success)
        {
            if (!success || string.IsNullOrEmpty(itemName)) return;

            if (!ItemPickupCounts.ContainsKey(itemName))
                ItemPickupCounts[itemName] = 0;

            ItemPickupCounts[itemName] += quantity;

            Instance.Logger.LogInfo(
                $"[InventoryTracker] Picked up {quantity}x '{itemName}'. " +
                $"Session total: {ItemPickupCounts[itemName]}"
            );
        }

        public void PrintSessionSummary()
        {
            Logger.LogInfo("=== Inventory Session Summary ===");
            foreach (var kvp in ItemPickupCounts)
            {
                Logger.LogInfo($"  {kvp.Key}: {kvp.Value} total");
            }
        }

        private void OnDestroy()
        {
            PrintSessionSummary();
            _harmony?.UnpatchSelf();
        }
    }

    [HarmonyPatch(typeof(InventoryManager), nameof(InventoryManager.AddItem))]
    public static class InventoryManager_AddItem_Postfix_Patch
    {
        [HarmonyPostfix]
        public static void Postfix(InventoryManager __instance, ItemData item, int quantity, bool __result)
        {
            if (item == null) return;
            InventoryTrackerPlugin.RecordItemAdded(item.itemName, quantity, __result);
        }
    }
}

