    [BepInPlugin("com.example.scaledhealth", "Scaled Health Mod", "1.0.0")]
    public class ScaledHealthPlugin : BaseUnityPlugin
    {
        public static ConfigEntry<float> BaseHealthOverride;
        public static ConfigEntry<float> HealthPerLevel;
        public static ConfigEntry<bool> ModEnabled;

        private Harmony _harmony;

        private void Awake()
        {
            ModEnabled = Config.Bind("General", "Enabled", true, "Enable or disable Scaled Health Mod.");

            BaseHealthOverride = Config.Bind(
                "Health",
                "BaseHealth",
                100f,
                new ConfigDescription("Base max health at level 1.", new AcceptableValueRange<float>(1f, 10000f))
            );

            HealthPerLevel = Config.Bind(
                "Health",
                "HealthPerLevel",
                15f,
                new ConfigDescription("Additional max health granted per player level.", new AcceptableValueRange<float>(0f, 500f))
            );

            if (ModEnabled.Value)
            {
                _harmony = new Harmony("com.example.scaledhealth");
                _harmony.PatchAll();
                Logger.LogInfo($"Scaled Health Mod loaded. Base: {BaseHealthOverride.Value}, Per Level: {HealthPerLevel.Value}");
            }
        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    [HarmonyPatch(typeof(PlayerStats), nameof(PlayerStats.GetMaxHealth))]
    public static class PlayerStats_GetMaxHealth_Postfix_Patch
    {
        [HarmonyPostfix]
        public static void Postfix(PlayerStats __instance, ref float __result)
        {
            if (!ScaledHealthPlugin.ModEnabled.Value) return;

            int playerLevel = __instance.Level;
            float scaledHealth = ScaledHealthPlugin.BaseHealthOverride.Value
                + (playerLevel - 1) * ScaledHealthPlugin.HealthPerLevel.Value;

            Debug.Log($"[ScaledHealthMod] Level {playerLevel}: Overriding MaxHealth {__result} -> {scaledHealth}");
            __result = scaledHealth;
        }
    }
}

