namespace SurvivalTimerMod
{
    [BepInPlugin("com.example.survivaltimer", "Survival Timer Mod", "1.0.0")]
    public class SurvivalTimerPlugin : BaseUnityPlugin
    {
        private Harmony _harmony;

        private void Awake()
        {
            _harmony = new Harmony("com.example.survivaltimer");
            _harmony.PatchAll();
            Logger.LogInfo("Survival Timer Mod loaded.");
        }

        private void OnDestroy() => _harmony?.UnpatchSelf();
    }

    /// <summary>
    /// Hooks into PlayerController.Start() to inject the SurvivalTimerComponent.
    /// </summary>
    [HarmonyPatch(typeof(PlayerController), "Start")]
    public static class PlayerController_Start_Patch
    {
        [HarmonyPostfix]
        public static void Postfix(PlayerController __instance)
        {
            if (__instance.GetComponent<SurvivalTimerComponent>() == null)
            {
                __instance.gameObject.AddComponent<SurvivalTimerComponent>();
                Debug.Log("[SurvivalTimerMod] SurvivalTimerComponent injected onto Player.");
            }
        }
    }

    /// <summary>
    /// Custom MonoBehaviour that tracks and displays survival time.
    /// </summary>
    public class SurvivalTimerComponent : MonoBehaviour
    {
        private float _elapsedTime = 0f;
        private float _nextLogTime = 60f;
        private GUIStyle _guiStyle;

        private void Start()
        {
            _guiStyle = new GUIStyle
            {
                fontSize = 16,
                fontStyle = FontStyle.Bold,
                alignment = TextAnchor.UpperRight
            };
            _guiStyle.normal.textColor = new Color(1f, 0.85f, 0.0f);
            Debug.Log("[SurvivalTimerMod] Timer started.");
        }

        private void Update()
        {
            _elapsedTime += Time.deltaTime;

            if (_elapsedTime >= _nextLogTime)
            {
                int minutes = Mathf.FloorToInt(_elapsedTime / 60f);
                Debug.Log($"[SurvivalTimerMod] Player has survived for {minutes} minute(s).");
                _nextLogTime += 60f;
            }
        }

        private void OnGUI()
        {
            int totalSeconds = Mathf.FloorToInt(_elapsedTime);
            int minutes = totalSeconds / 60;
            int seconds = totalSeconds % 60;

            string timeString = $"Survived: {minutes:D2}:{seconds:D2}";

            float screenWidth = Screen.width;
            Rect rect = new Rect(screenWidth - 200f, 10f, 190f, 30f);
            GUI.Label(rect, timeString, _guiStyle);
        }

        private void OnDestroy()
        {
            Debug.Log($"[SurvivalTimerMod] Component destroyed. Final survival time: {_elapsedTime:F1}s");
        }
    }
}
